function wrapText(text, maxWidth) {
  const words = text.trim().split(/\s+/);
  const lines = [];
  let currentLine = "";

  for (const word of words) {
    const nextLine = currentLine ? `${currentLine} ${word}` : word;
    if (nextLine.length > maxWidth && currentLine) {
      lines.push(currentLine);
      currentLine = word;
    } else {
      currentLine = nextLine;
    }
  }

  if (currentLine) {
    lines.push(currentLine);
  }

  return lines.length ? lines : [""];
}

function cowsay(message) {
  const lines = wrapText(message, 40);
  const width = Math.max(...lines.map((line) => line.length));
  const top = ` ${"_".repeat(width + 2)}`;
  const bottom = ` ${"-".repeat(width + 2)}`;

  const bubble = lines.map((line, index) => {
    const padded = line.padEnd(width, " ");
    const left = lines.length === 1 ? "<" : index === 0 ? "/" : index === lines.length - 1 ? "\\" : "|";
    const right = lines.length === 1 ? ">" : index === 0 ? "\\" : index === lines.length - 1 ? "/" : "|";
    return `${left} ${padded} ${right}`;
  });

  const cow = String.raw`
        \   ^__^
         \  (oo)\_______
            (__)\       )\/\
                ||----w |
                ||     ||
  `.trimEnd();

  return [top, ...bubble, bottom, cow].join("\n");
}

const message = process.argv.slice(2).join(" ") || "Moo from Codex";

console.log(cowsay(message));
